21	@Injectable()
22	export class NotificationService {
23	  constructor(
24	    private readonly txHost: TransactionHost<TransactionalAdapterTypeOrm>,
25	    private readonly emailNotificationService: EmailNotificationService,
26	    private readonly phoneNotificationService: PhoneNotificationService,
27	    private readonly inAppNotificationService: InAppNotificationService,
28	  ) {}
29	
30	  async send<T extends NotificationType>(
31	    userIds: string[] | 'admins',
32	    type: T,
33	    data: NotificationData<T>,
34	  ) {
35	    const media = NOTIFICATION_MEDIA_BY_TYPE[type];
36	
37	    let users: UserEntity[];
38	
39	    if (userIds === 'admins') {
40	      users = await this.txHost.tx
41	        .getRepository(UserEntity)
42	        .createQueryBuilder('user')
43	        .select(['user.id', 'user.email', 'user.phone', 'user.roles'])
44	        .where('user.roles && :roles', {
45	          roles: [UserRole.Admin, UserRole.SuperAdmin],
46	        })
47	        .getMany();
48	    } else {
49	      users = await this.txHost.tx.getRepository(UserEntity).findBy({
50	        id: In(userIds),
51	      });
52	    }
53	
54	    await Promise.all(
55	      media.map(async (m) =>
56	        this.getService(m).send(
57	          users,
58	          type,
59	          data,
60	          getNotificationContent(type, m, data),
61	        ),
62	      ),
63	    );
64	  }
65	
66	  private getService(media: NotificationMedia): AbstractNotificationService {
67	    switch (media) {
68	      case NotificationMedia.Email:
69	        return this.emailNotificationService;
70	      case NotificationMedia.Phone:
71	        return this.phoneNotificationService;
72	      case NotificationMedia.InApp:
73	        return this.inAppNotificationService;
74	    }
75	  }
76	
77	  async sendOtp(
78	    mediaType: MediaType,
79	    dto: {
80	      to: string;
81	      otp: string;
82	      reason: string;
83	      validForMinutes: number;
84	    },
85	  ) {
86	    switch (mediaType) {
87	      case MediaType.Email:
88	        return this.emailNotificationService.sendOtp(dto);
89	      case MediaType.Phone:
90	        return this.phoneNotificationService.sendOtp(dto);
91	    }
92	  }
93	
94	  async sendInvite(dto: {
95	    email: string;
96	    firstName: string;
97	    lastName: string;
98	    patronymic?: string | null;
99	    role: string;
100	    tempPassword: string;
101	  }) {
102	    await this.emailNotificationService.sendInvite(dto);
103	  }
104	}
