20	@Injectable()
21	export class EmailNotificationService implements AbstractNotificationService {
22	  private readonly logger = new Logger(EmailNotificationService.name);
23	  private mailerSend: MailerSend;
24	
25	  private emailService = createEmailService({
26	    defaultFrom: env.MAIL_SENDER_EMAIL,
27	    defaultReplyTo: env.MAIL_REPLY_TO_EMAIL,
28	    validateEmails: false,
29	  });
