37	  async send<T extends NotificationType>(
38	    users: UserEntity[],
39	    _type: T,
40	    _data: NotificationData<T>,
41	    content: MEDIA_TYPE_TO_CONTENT<NotificationMedia.Email>,
42	  ) {
43	    const { html, text } = await this.emailService.render(
44	      GeneralTemplate({
45	        message: content.text,
46	        link: content.link,
47	      }),
48	    );
49	
50	    await this.sendEmail({
51	      to: users.map((u) => u.email),
52	      subject: content.subject,
53	      html,
54	      text,
