59	    otp: string;
60	    reason: string;
61	    validForMinutes: number;
62	    to: string;
63	  }) {
64	    const { html, text } = await this.emailService.render(
65	      OtpTemplate({
66	        otp: dto.otp,
67	        reason: dto.reason,
68	        validForMinutes: dto.validForMinutes,
69	      }),
70	    );
71	
72	    await this.sendEmail({
73	      to: [dto.to],
74	      subject: 'LuxFlow OTP',
75	      html,
76	      text,
77	    });
78	  }
