80	  async sendInvite(dto: {
81	    email: string;
82	    firstName: string;
83	    lastName: string;
84	    patronymic?: string | null;
85	    role: string;
86	    tempPassword: string;
87	  }) {
88	    const { email, firstName, lastName, patronymic, role, tempPassword } = dto;
89	    const fullName = [firstName, patronymic, lastName].filter(Boolean).join(' ');
90	
91	    const { html, text } = await this.emailService.render(
92	      InviteTemplate({
93	        name: fullName,
94	        tempPassword,
95	        url: `${env.CORE_PUBLIC_URL}/sign-in`,
