129	  async sendContactFormTeamNotification(dto: {
130	    to: string;
131	    firstName: string;
132	    lastName: string;
133	    email: string;
134	    subject: string | null;
135	    message: string;
136	  }) {
137	    const lines = [
138	      `New contact form submission:`,
139	      ``,
140	      `Name: ${dto.firstName} ${dto.lastName}`,
141	      `Email: ${dto.email}`,
142	      dto.subject ? `Subject: ${dto.subject}` : null,
143	      ``,
144	      `Message:`,
145	      dto.message,
146	    ]
147	      .filter((line) => line !== null)
148	      .join('\n');
149	
150	    const { html, text } = await this.emailService.render(
151	      GeneralTemplate({ message: lines }),
152	    );
153	
154	    await this.sendEmail({
155	      to: [dto.to],
156	      subject: `Contact Form: ${dto.firstName} ${dto.lastName}`,
157	      html,
158	      text,
159	    });
160	  }
161	
162	  async sendContactFormConfirmation(dto: { to: string; firstName: string }) {
163	    const { html, text } = await this.emailService.render(
164	      GeneralTemplate({
165	        message: `Hi ${dto.firstName},\n\nThank you for reaching out. We have received your message and will get back to you shortly.`,
166	      }),
167	    );
168	
169	    await this.sendEmail({
170	      to: [dto.to],
171	      subject: 'We received your message — LuxFlow',
172	      html,
173	      text,
174	    });
175	  }
176	
177	  async suppressEmails(emails: string[], reason: string) {
178	    // todo: implement
179	    this.logger.log(
180	      `Suppressing emails: ${emails.join(', ')}. Reason: ${reason}`,
181	    );
182	  }
183	
184	  private async sendEmail({
185	    to,
186	    subject,
187	    html,
188	    text,
189	  }: {
190	    to: string[];
191	    subject: string;
192	    html: string;
193	    text?: string;
194	  }) {
195	    if (!env.MAIL_ENABLED) {
196	      return;
197	    }
198	
199	    const sentFrom = new Sender(env.MAIL_SENDER_EMAIL, 'LuxFlow');
200	    const replyTo = new Sender(env.MAIL_REPLY_TO_EMAIL, 'LuxFlow Admin');
201	
202	    const recipients = to.map((email) => new Recipient(email));
203	
204	    const emailParams = new EmailParams()
205	      .setFrom(sentFrom)
206	      .setTo(recipients)
207	      .setReplyTo(replyTo)
208	      .setSubject(subject)
209	      .setHtml(html)
210	      .setText(text ?? '');
211	
212	    try {
213	      this.logger.log('Sending email:', {
214	        to,
215	        subject,
216	      });
217	      const response = await this.mailerSend.email.send(emailParams);
218	      this.logger.log('Email sent:', response);
219	      return response;
220	    } catch (err) {
221	      this.logger.error('Error sending email:', err);
222	      throw err;
223	    }
224	  }
225	}
