22	
23	  async send<T extends NotificationType>(
24	    users: UserEntity[],
25	    type: T,
26	    data: NotificationData<T>,
27	    content: MEDIA_TYPE_TO_CONTENT<NotificationMedia.InApp>,
28	  ) {
29	    const repository = this.txHost.tx.getRepository(InAppNotificationEntity);
