43	  async getForUser(listQuery: ListQuery, userId: string) {
44	    const repository = this.txHost.tx.getRepository(InAppNotificationEntity);
45	
46	    return repository.find({
47	      where: { userId },
48	      order: { createdAt: 'DESC' },
49	      take: listQuery.take,
50	      skip: listQuery.skip,
51	    });
52	  }
53	
54	  async clearAll(userId: string) {
55	    const repository = this.txHost.tx.getRepository(InAppNotificationEntity);
56	
57	    await repository.softDelete({ userId });
58	  }
59	
60	  async markRead(userId: string, notificationIds: string[]) {
61	    const repository = this.txHost.tx.getRepository(InAppNotificationEntity);
62	
63	    const notifications = await repository.find({
64	      where: { id: In(notificationIds), userId },
65	    });
66	
67	    if (notifications.length !== notificationIds.length) {
68	      throw new BadRequestException('Notification not found');
69	    }
70	
71	    await repository.save(
72	      notificationIds.map((id) => ({
73	        id,
74	        readAt: new Date(),
75	      })),
76	    );
77	  }
78	}
