9	import { AUTHENTICATION_REQUEST_CONTENT } from './authentication-request.content';
10	import { BUYBACK_REQUEST_EVENT_CONTENT } from './buyback-request-event.content';
11	import { BUYBACK_EXTEND_REMINDER_CONTENT } from './buyback-extent-reminder.content';
12	import { BUYBACK_DEADLINE_COMING_UP_CONTENT } from './buyback-deadline-coming-up.content';
13	import { BUYBACK_UNSETTLED_CONTENT } from './buyback-unsettled.content';
14	import { KYC_REMINDER_CONTENT } from './kyc-reminder.content';
15	import { KYC_APPROVED_CONTENT } from './kyc-approved.content';
16	import { KYC_REJECTED_CONTENT } from './kyc-rejected.content';
17	import { BUYBACK_REQUEST_ADMIN_EVENT_CONTENT } from './buyback-request-admin-event.content';
18	import { BUYBACK_ADMIN_EVENT_CONTENT } from './buyback-admin-event.content';
19	import { BUYBACK_EXTENDED_BY_ADMIN_CONTENT } from './buyback-extended-by-admin.content';
20	import { BUYBACK_OFFER_EXPIRED_CONTENT } from './buyback-offer-expired.content';
21	import { TICKET_CLOSED_CONTENT } from './ticket-closed.content';
22	import { BUYBACK_WEEKLY_EXTENSION_APPROVED_CONTENT } from './buyback-final-extension-approved.content';
23	import { BUYBACK_WEEKLY_EXTENSION_REJECTED_CONTENT } from './buyback-final-extension-rejected.content';
24	
25	const NOTIFICATION_CONTENT: Record<NotificationType, NotificationContentType> =
26	  {
27	    [NotificationType.AuthenticationRequest]: AUTHENTICATION_REQUEST_CONTENT,
28	    [NotificationType.BuybackRequestMajorEvent]: BUYBACK_REQUEST_EVENT_CONTENT,
29	    [NotificationType.BuybackRequestMinorEvent]: BUYBACK_REQUEST_EVENT_CONTENT,
30	    [NotificationType.BuybackExtendReminder]: BUYBACK_EXTEND_REMINDER_CONTENT,
31	    [NotificationType.BuybackDeadlineComingUp]:
32	      BUYBACK_DEADLINE_COMING_UP_CONTENT,
33	    [NotificationType.BuybackUnsettled]: BUYBACK_UNSETTLED_CONTENT,
34	    [NotificationType.KycReminder]: KYC_REMINDER_CONTENT,
35	    [NotificationType.KycApproved]: KYC_APPROVED_CONTENT,
36	    [NotificationType.KycRejected]: KYC_REJECTED_CONTENT,
37	    [NotificationType.BuybackRequestAdminMinorEvent]:
38	      BUYBACK_REQUEST_ADMIN_EVENT_CONTENT,
39	    [NotificationType.BuybackRequestAdminMajorEvent]:
40	      BUYBACK_REQUEST_ADMIN_EVENT_CONTENT,
41	    [NotificationType.BuybackOfferExpired]: BUYBACK_OFFER_EXPIRED_CONTENT,
42	    [NotificationType.BuybackExtendedByAdmin]:
43	      BUYBACK_EXTENDED_BY_ADMIN_CONTENT,
44	    [NotificationType.BuybackAdminMinorEvent]: BUYBACK_ADMIN_EVENT_CONTENT,
45	    [NotificationType.BuybackAdminMajorEvent]: BUYBACK_ADMIN_EVENT_CONTENT,
46	    [NotificationType.BuybackFinalExtensionApproved]:
47	      BUYBACK_WEEKLY_EXTENSION_APPROVED_CONTENT,
48	    [NotificationType.BuybackFinalExtensionRejected]:
49	      BUYBACK_WEEKLY_EXTENSION_REJECTED_CONTENT,
50	    [NotificationType.TicketClosed]: TICKET_CLOSED_CONTENT,
51	  };
52	
53	export function getNotificationContent<
54	  T extends NotificationType,
55	  M extends NotificationMedia,
56	>(type: T, media: M, data: NotificationData<T>) {
57	  return NOTIFICATION_CONTENT[type][media](data) as MEDIA_TYPE_TO_CONTENT<M>;
58	}
